import{_ as s,o as a,c as e,Q as n}from"./chunks/framework.4a66d6f9.js";const E=JSON.parse('{"title":"Linux私钥登陆提示server refused our key","description":"","frontmatter":{},"headers":[],"relativePath":"linux/env/Linux私钥登陆提示server refused our key.md","filePath":"linux/env/Linux私钥登陆提示server refused our key.md","lastUpdated":1704522520000}'),l={name:"linux/env/Linux私钥登陆提示server refused our key.md"},o=n(`<h1 id="linux私钥登陆提示server-refused-our-key" tabindex="-1">Linux私钥登陆提示server refused our key <a class="header-anchor" href="#linux私钥登陆提示server-refused-our-key" aria-label="Permalink to &quot;Linux私钥登陆提示server refused our key&quot;">​</a></h1><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>家庭内网装了个物理机的Ubuntu server，用的最新版本的22.04，然后用windows端的mobaxterm和navicat使用ssh私钥连接内网服务器时返回了<code>Server refused our key</code>的异常</p><h2 id="问题原因" tabindex="-1">问题原因 <a class="header-anchor" href="#问题原因" aria-label="Permalink to &quot;问题原因&quot;">​</a></h2><p><code>openssh 8.8</code>开始默认禁用了使用<code>SHA-1</code>哈希算法的<code>RSA</code>签名,看了一下ubuntu server 22.04的默认openssh版本：</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#B392F0;">➜</span><span style="color:#E1E4E8;">  </span><span style="color:#9ECBFF;">~</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">ssh</span><span style="color:#E1E4E8;"> </span><span style="color:#79B8FF;">-V</span></span>
<span class="line"><span style="color:#B392F0;">OpenSSH_8.9p1</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">Ubuntu-3,</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">OpenSSL</span><span style="color:#E1E4E8;"> </span><span style="color:#79B8FF;">3.0</span><span style="color:#9ECBFF;">.2</span><span style="color:#E1E4E8;"> </span><span style="color:#79B8FF;">15</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">Mar</span><span style="color:#E1E4E8;"> </span><span style="color:#79B8FF;">2022</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#6F42C1;">➜</span><span style="color:#24292E;">  </span><span style="color:#032F62;">~</span><span style="color:#24292E;"> </span><span style="color:#032F62;">ssh</span><span style="color:#24292E;"> </span><span style="color:#005CC5;">-V</span></span>
<span class="line"><span style="color:#6F42C1;">OpenSSH_8.9p1</span><span style="color:#24292E;"> </span><span style="color:#032F62;">Ubuntu-3,</span><span style="color:#24292E;"> </span><span style="color:#032F62;">OpenSSL</span><span style="color:#24292E;"> </span><span style="color:#005CC5;">3.0</span><span style="color:#032F62;">.2</span><span style="color:#24292E;"> </span><span style="color:#005CC5;">15</span><span style="color:#24292E;"> </span><span style="color:#032F62;">Mar</span><span style="color:#24292E;"> </span><span style="color:#005CC5;">2022</span></span></code></pre></div><blockquote><p><a href="https://www.openssh.com/txt/release-8.8" target="_blank" rel="noreferrer">https://www.openssh.com/txt/release-8.8</a></p><p>This release disables RSA signatures using the SHA-1 hash algorithm by default. This change has been made as the SHA-1 hash algorithm is cryptographically broken, and it is possible to create chosen-prefix hash collisions for &lt;USD$50K [1]</p></blockquote><h2 id="解决方案" tabindex="-1">解决方案 <a class="header-anchor" href="#解决方案" aria-label="Permalink to &quot;解决方案&quot;">​</a></h2><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#B392F0;">vim</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">/etc/ssh/sshd_config</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># 添加配置</span></span>
<span class="line"><span style="color:#B392F0;">PubkeyAcceptedKeyTypes</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">+ssh-rsa</span></span>
<span class="line"></span>
<span class="line"></span>
<span class="line"><span style="color:#B392F0;">systemctl</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">restart</span><span style="color:#E1E4E8;"> </span><span style="color:#9ECBFF;">sshd</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#6F42C1;">vim</span><span style="color:#24292E;"> </span><span style="color:#032F62;">/etc/ssh/sshd_config</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># 添加配置</span></span>
<span class="line"><span style="color:#6F42C1;">PubkeyAcceptedKeyTypes</span><span style="color:#24292E;"> </span><span style="color:#032F62;">+ssh-rsa</span></span>
<span class="line"></span>
<span class="line"></span>
<span class="line"><span style="color:#6F42C1;">systemctl</span><span style="color:#24292E;"> </span><span style="color:#032F62;">restart</span><span style="color:#24292E;"> </span><span style="color:#032F62;">sshd</span></span></code></pre></div>`,9),p=[o];function r(t,c,i,y,d,h){return a(),e("div",null,p)}const F=s(l,[["render",r]]);export{E as __pageData,F as default};
